     1→#!/usr/bin/env node
     2→/**
     3→ * NIM Model Audit Script — Tests ALL registered NIM models
     4→ * Tests each model with a real API call and logs status, response time, errors
     5→ */
     6→
     7→const OpenAI = require('openai');
     8→const fetch = require('node-fetch');
     9→const FormData = require('form-data');
    10→
    11→const NIM_API_KEY = process.env.NVIDIA_NIM_API_KEY;
    12→const NIM_BASE = process.env.NIM_BASE_URL || 'https://integrate.api.nvidia.com/v1';
    13→
    14→if (!NIM_API_KEY) {
    15→  console.error('ERROR: NVIDIA_NIM_API_KEY not set');
    16→  process.exit(1);
    17→}
    18→
    19→const nimClient = new OpenAI({ baseURL: NIM_BASE, apiKey: NIM_API_KEY });
    20→
    21→// All LLM models to test
    22→const LLM_MODELS = [
    23→  { key: 'nemotron_super', model: 'nvidia/llama-3.3-nemotron-super-49b-v1', integrated: true },
    24→  { key: 'nemotron_super_v1.5', model: 'nvidia/llama-3.3-nemotron-super-49b-v1.5', integrated: false },
    25→  { key: 'deepseek_v3', model: 'deepseek-ai/deepseek-v3p2', integrated: true },
    26→  { key: 'kimi_k2.5', model: 'moonshot-ai/kimi-k2.5', integrated: true },
    27→  { key: 'step_flash', model: 'stepfun-ai/step-3.5-flash', integrated: true },
    28→  { key: 'gpt_oss_120b', model: 'openai/gpt-oss-120b', integrated: true },
    29→  { key: 'gpt_oss_20b', model: 'openai/gpt-oss-20b', integrated: false },
    30→  { key: 'nano_9b', model: 'nvidia/nemotron-nano-8b-v2', integrated: true },
    31→  { key: 'deepseek_v3_1', model: 'deepseek-ai/deepseek-v3p1', integrated: true },
    32→  { key: 'mistral_small', model: 'mistralai/mistral-small-24b-instruct-2501', integrated: true },
    33→  { key: 'qwen_72b', model: 'qwen/qwen2.5-72b-instruct', integrated: true },
    34→  { key: 'deepseek_r1', model: 'deepseek-ai/deepseek-r1', integrated: true },
    35→  { key: 'qwq_32b', model: 'qwen/qwq-32b', integrated: true },
    36→  { key: 'llama_3.3_70b', model: 'meta/llama-3.3-70b-instruct', integrated: false },
    37→  { key: 'llama_3.1_8b', model: 'meta/llama-3.1-8b-instruct', integrated: false },
    38→  { key: 'llama_3.1_70b', model: 'meta/llama-3.1-70b-instruct', integrated: false },
    39→  { key: 'llama_3.1_405b', model: 'meta/llama-3.1-405b-instruct', integrated: false },
    40→  { key: 'gemma_3_27b', model: 'google/gemma-3-27b-it', integrated: true },
    41→  { key: 'phi_4_mini', model: 'microsoft/phi-4-mini-instruct', integrated: false },
    42→  { key: 'granite_3.3_8b', model: 'ibm/granite-3.3-8b-instruct', integrated: false },
    43→  { key: 'nemotron_nano_30b', model: 'nvidia/nemotron-3-nano-30b-a3b', integrated: false },
    44→  { key: 'minimax_m2', model: 'minimax/minimax-m2', integrated: false },
    45→  { key: 'glm_4.7', model: 'zhipu-ai/glm-4.7', integrated: false },
    46→  { key: 'nemotron_ultra_253b', model: 'nvidia/llama-3.1-nemotron-ultra-253b-v1', integrated: false },
    47→  { key: 'kimi_k2_instruct', model: 'moonshot-ai/kimi-k2-instruct', integrated: false },
    48→  { key: 'seed_oss_36b', model: 'bytedance/seed-oss-36b-instruct', integrated: false },
    49→  { key: 'devstral_123b', model: 'mistralai/devstral-2-123b', integrated: false },
    50→];
    51→
    52→// Vision models to test
    53→const VISION_MODELS = [
    54→  { key: 'cosmos_reason2', model: 'nvidia/cosmos-reason2-8b', integrated: true },
    55→  { key: 'nemotron_vl', model: 'nvidia/nemotron-nano-12b-v2-vl', integrated: true },
    56→  { key: 'kimi_vision', model: 'moonshot-ai/kimi-k2.5', integrated: true },
    57→  { key: 'gemma_vision', model: 'google/gemma-3-27b-it', integrated: true },
    58→];
    59→
    60→// Embedding models
    61→const EMBED_MODELS = [
    62→  { key: 'embed_qa', model: 'nvidia/llama-3.2-nv-embedqa-1b-v2', integrated: true },
    63→  { key: 'embed_vl', model: 'nvidia/llama-nemotron-embed-vl-1b-v2', integrated: true },
    64→];
    65→
    66→// Reranking models — use REST /v1/ranking
    67→const RERANK_MODELS = [
    68→  { key: 'rerank_qa', model: 'nvidia/llama-3.2-nv-rerankqa-1b-v2', integrated: true },
    69→  { key: 'rerank_vl', model: 'nvidia/llama-nemotron-rerank-vl-1b-v2', integrated: true },
    70→];
    71→
    72→// Safety models
    73→const SAFETY_MODELS = [
    74→  { key: 'safety_guard', model: 'nvidia/llama-3.1-nemotron-safety-guard-8b-v3', integrated: true },
    75→  { key: 'safety_reasoning', model: 'nvidia/nemotron-content-safety-reasoning-4b', integrated: true },
    76→];
    77→
    78→const results = [];
    79→
    80→async function testLLM(entry) {
    81→  const start = Date.now();
    82→  try {
    83→    const response = await Promise.race([
    84→      nimClient.chat.completions.create({
    85→        model: entry.model,
    86→        messages: [{ role: 'user', content: 'Say hello in one word.' }],
    87→        max_tokens: 20,
    88→        temperature: 0.1,
    89→      }),
    90→      new Promise((_, reject) => setTimeout(() => reject(new Error('TIMEOUT_12s')), 12000)),
    91→    ]);
    92→    const ms = Date.now() - start;
    93→    const text = response.choices?.[0]?.message?.content || '';
    94→    results.push({
    95→      modality: 'LLM', key: entry.key, model: entry.model,
    96→      status: '✅ Working', responseMs: ms, integrated: entry.integrated,
    97→      note: text.substring(0, 50),
    98→    });
    99→  } catch (err) {
   100→    const ms = Date.now() - start;
   101→    const status = err.status || err.statusCode || 0;
   102→    const msg = err.message || String(err);
   103→    let verdict = '❌ Dead';
   104→    if (msg.includes('TIMEOUT')) verdict = '⚠️ Slow (timeout)';
   105→    else if (status === 404) verdict = '❌ 404 Not Found';
   106→    else if (status === 429) verdict = '⚠️ Rate Limited';
   107→    else if (status === 401 || status === 403) verdict = '❌ Auth Error';
   108→    results.push({
   109→      modality: 'LLM', key: entry.key, model: entry.model,
   110→      status: verdict, responseMs: ms, integrated: entry.integrated,
   111→      note: `[${status}] ${msg.substring(0, 100)}`,
   112→    });
   113→  }
   114→}
   115→
   116→async function testEmbedding(entry) {
   117→  const start = Date.now();
   118→  try {
   119→    const response = await Promise.race([
   120→      nimClient.embeddings.create({
   121→        model: entry.model,
   122→        input: 'Hello world test embedding',
   123→      }),
   124→      new Promise((_, reject) => setTimeout(() => reject(new Error('TIMEOUT_12s')), 12000)),
   125→    ]);
