      'nim_nemotron_super': NIM_MODELS.llm_super,
      'nim_qwq': NIM_MODELS.reasoning_qwq,
      'nim_nemotron_vl': NIM_MODELS.vision_nemotron_vl,
      'nim_gemma_vision': NIM_MODELS.vision_gemma,
      // Groq models
      'groq_llama_70b': 'llama-3.3-70b-versatile',
