  // ─── Active Model Verification ──────────────────────────────
  // Makes REAL API calls to verify each NIM model actually responds.
  // Call on-demand from /api/ai-health/verify — not on every health check.

  async verifyModels() {
    const results = [];
    const timeout = (ms) => new Promise((_, rej) => setTimeout(() => rej(new Error('TIMEOUT')), ms));

    // Helper: test embedding model
    const testEmbed = async (key, model) => {
      const start = Date.now();
      try {
        const res = await Promise.race([
          this.clients.nim.embeddings.create({
            model,
            input: 'test embedding verification',
            extra_body: { input_type: 'query' },
          }),
          timeout(10000),
        ]);
        const dim = res.data?.[0]?.embedding?.length || 0;
        results.push({ modality: 'embedding', key, model, status: 'working', ms: Date.now() - start, note: `${dim} dims` });
      } catch (err) {
        results.push({ modality: 'embedding', key, model, status: 'dead', ms: Date.now() - start, error: `${err.status || err.name}: ${(err.message || '').substring(0, 100)}` });
      }
    };

    // Helper: test safety model
    const testSafety = async (key, model) => {
      const start = Date.now();
      try {
        const res = await Promise.race([
          this.clients.nim.chat.completions.create({
            model,
            messages: [
              { role: 'system', content: 'Classify safety. Respond: {"safe": true}' },
              { role: 'user', content: 'Hello' },
            ],
            max_tokens: 50,
            temperature: 0.1,
          }),
          timeout(10000),
        ]);
        results.push({ modality: 'safety', key, model, status: 'working', ms: Date.now() - start, note: (res.choices?.[0]?.message?.content || '').substring(0, 60) });
      } catch (err) {
        results.push({ modality: 'safety', key, model, status: 'dead', ms: Date.now() - start, error: `${err.status || err.name}: ${(err.message || '').substring(0, 100)}` });
      }
    };

    // Run all verifications in parallel
    const tasks = [];
    if (this.nimAvailable) {
      tasks.push(testEmbed('nim_embed_qa', NIM_MODELS.embed_qa));
      tasks.push(testEmbed('nim_embed_vl', NIM_MODELS.embed_vl));
      tasks.push(testSafety('nim_safety_guard', NIM_MODELS.safety_guard));
      tasks.push(testSafety('nim_safety_reasoning', NIM_MODELS.safety_reasoning));
    }

    await Promise.all(tasks);

    // Cache results for dashboard
    this._lastVerification = {
      timestamp: new Date().toISOString(),
      results,
    };

    console.log(`[ai-provider] Model verification complete: ${results.filter(r => r.status === 'working').length}/${results.length} working`);
    return this._lastVerification;
  }

  // ─── Reset (for testing) ──────────────────────────────────────

  resetCircuitBreakers() {
    this.failures = {};
    console.log('[ai-provider] All circuit breakers reset');
  }
}

